PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS schema_meta (key TEXT PRIMARY KEY, value TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS messages (id INTEGER PRIMARY KEY AUTOINCREMENT, discord_msg_id TEXT UNIQUE NOT NULL, scope_type TEXT NOT NULL CHECK (scope_type IN ('dm','group','guild')), scope_id TEXT NOT NULL, guild_id TEXT, author_id TEXT NOT NULL, author_name TEXT NOT NULL, content TEXT NOT NULL, is_command INTEGER NOT NULL DEFAULT 0, is_authorized INTEGER NOT NULL DEFAULT 0, triggered_bot INTEGER NOT NULL DEFAULT 0, reply_to_id TEXT, timestamp_utc TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_messages_scope_ts ON messages(scope_type, scope_id, timestamp_utc);
CREATE INDEX IF NOT EXISTS idx_messages_author_ts ON messages(author_id, timestamp_utc);
CREATE VIRTUAL TABLE IF NOT EXISTS messages_fts USING fts5(content, author_name, scope_id, content='messages', content_rowid=id, tokenize='unicode61 remove_diacritics 2');
CREATE TRIGGER IF NOT EXISTS ai_messages AFTER INSERT ON messages BEGIN
  INSERT INTO messages_fts(rowid, content, author_name, scope_id) VALUES (new.id, new.content, new.author_name, new.scope_id);
END;
CREATE TRIGGER IF NOT EXISTS ad_messages AFTER DELETE ON messages BEGIN
  INSERT INTO messages_fts(messages_fts, rowid, content, author_name, scope_id) VALUES ('delete', old.id, old.content, old.author_name, old.scope_id);
END;
CREATE TRIGGER IF NOT EXISTS au_messages AFTER UPDATE ON messages BEGIN
  INSERT INTO messages_fts(messages_fts, rowid, content, author_name, scope_id) VALUES ('delete', old.id, old.content, old.author_name, old.scope_id);
  INSERT INTO messages_fts(rowid, content, author_name, scope_id) VALUES (new.id, new.content, new.author_name, new.scope_id);
END;
CREATE TABLE IF NOT EXISTS prompts (id INTEGER PRIMARY KEY AUTOINCREMENT, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','dm','group','guild')), scope_id TEXT, body TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by TEXT NOT NULL);
CREATE UNIQUE INDEX IF NOT EXISTS uq_prompts_global ON prompts(scope_type) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_prompts_scoped ON prompts(scope_type, scope_id) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS prompt_history (id INTEGER PRIMARY KEY AUTOINCREMENT, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','dm','group','guild')), scope_id TEXT, old_body TEXT, new_body TEXT NOT NULL, updated_at TEXT NOT NULL, updated_by TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_prompt_history_scope_ts ON prompt_history(scope_type, scope_id, updated_at);
CREATE TABLE IF NOT EXISTS permissions (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','dm','group','guild')), scope_id TEXT, level TEXT NOT NULL CHECK (level IN ('root','admin','user','blocked')), added_at TEXT NOT NULL);
CREATE UNIQUE INDEX IF NOT EXISTS uq_permissions_global ON permissions(user_id, scope_type) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_permissions_scoped ON permissions(user_id, scope_type, scope_id) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS commands_log (id INTEGER PRIMARY KEY AUTOINCREMENT, source TEXT NOT NULL CHECK (source IN ('discord','panel')), user_id TEXT NOT NULL, scope_type TEXT NOT NULL, scope_id TEXT, command TEXT NOT NULL, args TEXT, accepted INTEGER NOT NULL, reason TEXT, timestamp_utc TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS ollama_log (id INTEGER PRIMARY KEY AUTOINCREMENT, scope_type TEXT NOT NULL, scope_id TEXT, model TEXT NOT NULL, prompt_tokens INTEGER, completion_tokens INTEGER, latency_ms INTEGER, request_json TEXT NOT NULL, response_json TEXT, error TEXT, timestamp_utc TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS bot_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, level TEXT NOT NULL CHECK (level IN ('trace','debug','info','warn','error')), component TEXT NOT NULL, message TEXT NOT NULL, detail_json TEXT, scope_type TEXT, scope_id TEXT, timestamp_utc TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_bot_logs_level_ts ON bot_logs(level, timestamp_utc);
CREATE INDEX IF NOT EXISTS idx_bot_logs_component_ts ON bot_logs(component, timestamp_utc);
CREATE TABLE IF NOT EXISTS context_state (scope_type TEXT NOT NULL, scope_id TEXT NOT NULL, last_wake_utc TEXT, rolling_summary TEXT, last_message_id INTEGER, PRIMARY KEY(scope_type, scope_id));
CREATE TABLE IF NOT EXISTS memories (int_memory_id INTEGER PRIMARY KEY AUTOINCREMENT, str_discord_id TEXT NOT NULL CHECK (length(str_discord_id) BETWEEN 15 AND 22 AND str_discord_id NOT GLOB '*[^0-9]*'), str_annotations TEXT NOT NULL, array_tags TEXT CHECK (array_tags IS NULL OR json_valid(array_tags)), float_confidence REAL NOT NULL DEFAULT 0.7 CHECK (float_confidence BETWEEN 0.0 AND 1.0), str_created_utc TEXT NOT NULL, str_created_by TEXT NOT NULL, int_superseded_by INTEGER, FOREIGN KEY(int_superseded_by) REFERENCES memories(int_memory_id));
CREATE INDEX IF NOT EXISTS idx_memories_discord ON memories(str_discord_id, int_superseded_by);
CREATE VIRTUAL TABLE IF NOT EXISTS memories_fts USING fts5(str_annotations, array_tags, str_discord_id, content='memories', content_rowid='int_memory_id');
CREATE TRIGGER IF NOT EXISTS ai_memories AFTER INSERT ON memories BEGIN INSERT INTO memories_fts(rowid,str_annotations,array_tags,str_discord_id) VALUES(new.int_memory_id,new.str_annotations,new.array_tags,new.str_discord_id); END;
CREATE TRIGGER IF NOT EXISTS ad_memories AFTER DELETE ON memories BEGIN INSERT INTO memories_fts(memories_fts,rowid,str_annotations,array_tags,str_discord_id) VALUES('delete',old.int_memory_id,old.str_annotations,old.array_tags,old.str_discord_id); END;
CREATE TRIGGER IF NOT EXISTS au_memories AFTER UPDATE ON memories BEGIN INSERT INTO memories_fts(memories_fts,rowid,str_annotations,array_tags,str_discord_id) VALUES('delete',old.int_memory_id,old.str_annotations,old.array_tags,old.str_discord_id); INSERT INTO memories_fts(rowid,str_annotations,array_tags,str_discord_id) VALUES(new.int_memory_id,new.str_annotations,new.array_tags,new.str_discord_id); END;
CREATE TABLE IF NOT EXISTS memory_events (id INTEGER PRIMARY KEY AUTOINCREMENT, event_type TEXT NOT NULL, scope_type TEXT, scope_id TEXT, user_id TEXT, user_name TEXT, role TEXT NOT NULL CHECK (role IN ('user','assistant','system','tool','task','operator')), content TEXT NOT NULL, metadata_json TEXT, timestamp_utc TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_memory_events_ts ON memory_events(timestamp_utc);
CREATE INDEX IF NOT EXISTS idx_memory_events_scope_ts ON memory_events(scope_type, scope_id, timestamp_utc);
CREATE TABLE IF NOT EXISTS news_items (id INTEGER PRIMARY KEY AUTOINCREMENT, url TEXT NOT NULL UNIQUE, title TEXT NOT NULL, source TEXT NOT NULL, source_kind TEXT NOT NULL CHECK (source_kind IN ('grounding','exploratory')), published_at_utc TEXT, first_seen_utc TEXT NOT NULL, last_seen_utc TEXT NOT NULL, last_posted_utc TEXT, posted_count INTEGER NOT NULL DEFAULT 0, metadata_json TEXT);
CREATE INDEX IF NOT EXISTS idx_news_items_posted ON news_items(last_posted_utc);
CREATE INDEX IF NOT EXISTS idx_news_items_source_seen ON news_items(source, last_seen_utc);
CREATE TABLE IF NOT EXISTS discord_identity_map (snowflake TEXT PRIMARY KEY, label TEXT NOT NULL CHECK (length(label)<=255), kind TEXT, source TEXT NOT NULL DEFAULT 'operator', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS panel_chat (id INTEGER PRIMARY KEY AUTOINCREMENT, role TEXT NOT NULL CHECK (role IN ('operator','assistant','system')), content TEXT NOT NULL, tool_calls_json TEXT, timestamp_utc TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS model_overrides (id INTEGER PRIMARY KEY AUTOINCREMENT, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','dm','group','guild')), scope_id TEXT, model TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE UNIQUE INDEX IF NOT EXISTS uq_model_overrides_global ON model_overrides(scope_type) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_model_overrides_scoped ON model_overrides(scope_type, scope_id) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS reasoning_overrides (id INTEGER PRIMARY KEY AUTOINCREMENT, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','dm','group','guild')), scope_id TEXT, mode TEXT NOT NULL CHECK (mode IN ('on','off','low','medium','high')), updated_at TEXT NOT NULL);
CREATE UNIQUE INDEX IF NOT EXISTS uq_reasoning_overrides_global ON reasoning_overrides(scope_type) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_reasoning_overrides_scoped ON reasoning_overrides(scope_type, scope_id) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS agent_tasks (id INTEGER PRIMARY KEY AUTOINCREMENT, kind TEXT NOT NULL, name TEXT, prompt TEXT NOT NULL, status TEXT NOT NULL CHECK (status IN ('queued','running','completed','failed')), requested_by TEXT NOT NULL, source TEXT NOT NULL CHECK (source IN ('discord','panel','scheduler')), scope_type TEXT NOT NULL, scope_id TEXT, backend TEXT NOT NULL DEFAULT 'ollama', enabled INTEGER NOT NULL DEFAULT 0, schedule_minutes INTEGER, next_run_utc TEXT, last_run_utc TEXT, run_count INTEGER NOT NULL DEFAULT 0, max_runs INTEGER, provider_id INTEGER, model TEXT, parameter_profile_id INTEGER, bot_entry_id INTEGER, runtime_kind TEXT, created_by_display TEXT, target_scope_type TEXT, target_scope_id TEXT, result TEXT, error TEXT, created_at TEXT NOT NULL, updated_at TEXT, started_at TEXT, completed_at TEXT);
CREATE INDEX IF NOT EXISTS idx_agent_tasks_status_created ON agent_tasks(status, created_at);
CREATE TABLE IF NOT EXISTS agent_assets (id INTEGER PRIMARY KEY AUTOINCREMENT, asset_type TEXT NOT NULL CHECK (asset_type IN ('tool','skill')), name TEXT NOT NULL, description TEXT NOT NULL, body TEXT, scope_type TEXT NOT NULL DEFAULT 'global' CHECK (scope_type IN ('global','dm','group','guild')), scope_id TEXT, enabled INTEGER NOT NULL DEFAULT 1, is_builtin INTEGER NOT NULL DEFAULT 0, schema_json TEXT, executor_name TEXT, snapshot_version TEXT, globally_disabled INTEGER NOT NULL DEFAULT 0, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
CREATE TABLE IF NOT EXISTS tool_snapshots (id INTEGER PRIMARY KEY AUTOINCREMENT, version TEXT NOT NULL UNIQUE, tools_json TEXT NOT NULL, created_at TEXT NOT NULL, created_by TEXT NOT NULL, applied_at TEXT);
CREATE TABLE IF NOT EXISTS task_snapshots (id INTEGER PRIMARY KEY AUTOINCREMENT, version TEXT NOT NULL UNIQUE, tasks_json TEXT NOT NULL, created_at TEXT NOT NULL, created_by TEXT NOT NULL, applied_at TEXT);
CREATE TABLE IF NOT EXISTS service_providers (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, provider_type TEXT NOT NULL CHECK (provider_type IN ('ollama','openrouter','openai_compatible')), base_url TEXT NOT NULL, enabled INTEGER NOT NULL DEFAULT 1, default_model TEXT NOT NULL, api_key TEXT, api_key_fingerprint TEXT, api_key_last4 TEXT, auth_scheme TEXT NOT NULL DEFAULT 'bearer', headers_json TEXT, supports_tools INTEGER NOT NULL DEFAULT 0, supports_reasoning INTEGER NOT NULL DEFAULT 0, supports_temperature INTEGER NOT NULL DEFAULT 1, supports_streaming INTEGER NOT NULL DEFAULT 0, timeout_s REAL NOT NULL DEFAULT 120.0, created_at TEXT NOT NULL, updated_at TEXT, last_test_at TEXT, last_test_ok INTEGER, last_error TEXT);
CREATE TABLE IF NOT EXISTS provider_models (id INTEGER PRIMARY KEY AUTOINCREMENT, provider_id INTEGER NOT NULL REFERENCES service_providers(id) ON DELETE CASCADE, model TEXT NOT NULL, display_name TEXT, enabled INTEGER NOT NULL DEFAULT 1, context_window_tokens INTEGER, supports_tools INTEGER, supports_reasoning INTEGER, supports_vision INTEGER, supports_json INTEGER, input_cost_per_million REAL, output_cost_per_million REAL, metadata_json TEXT, created_at TEXT NOT NULL, updated_at TEXT, UNIQUE(provider_id, model));
CREATE TABLE IF NOT EXISTS provider_parameters (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, description TEXT, params_json TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
CREATE TABLE IF NOT EXISTS provider_calls (id INTEGER PRIMARY KEY AUTOINCREMENT, provider_id INTEGER REFERENCES service_providers(id), provider_name TEXT NOT NULL, provider_type TEXT NOT NULL, model TEXT NOT NULL, scope_type TEXT NOT NULL, scope_id TEXT, bot_entry_id INTEGER, task_id INTEGER, task_run_id INTEGER, source TEXT NOT NULL CHECK (source IN ('discord','panel','task','news','roxanne','test','scheduler')), request_json TEXT NOT NULL, response_json TEXT, sent_params_json TEXT, ignored_params_json TEXT, prompt_tokens INTEGER, completion_tokens INTEGER, total_tokens INTEGER, latency_ms INTEGER, error TEXT, timestamp_utc TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_provider_calls_provider_ts ON provider_calls(provider_id, timestamp_utc);
CREATE INDEX IF NOT EXISTS idx_provider_calls_scope_ts ON provider_calls(scope_type, scope_id, timestamp_utc);
CREATE TABLE IF NOT EXISTS bot_entries (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, description TEXT, enabled INTEGER NOT NULL DEFAULT 1, persona TEXT, default_scope_type TEXT NOT NULL DEFAULT 'global', default_scope_id TEXT, created_at TEXT NOT NULL, updated_at TEXT);
CREATE TABLE IF NOT EXISTS bot_entry_bindings (id INTEGER PRIMARY KEY AUTOINCREMENT, bot_entry_id INTEGER NOT NULL REFERENCES bot_entries(id) ON DELETE CASCADE, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','guild','channel','dm','group','user')), scope_id TEXT, provider_id INTEGER REFERENCES service_providers(id), model TEXT, parameter_profile_id INTEGER REFERENCES provider_parameters(id), instructions_id INTEGER, enabled INTEGER NOT NULL DEFAULT 1, priority INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT, UNIQUE(bot_entry_id, scope_type, scope_id));
CREATE TABLE IF NOT EXISTS scope_profiles (id INTEGER PRIMARY KEY AUTOINCREMENT, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','guild','channel','dm','group','user')), scope_id TEXT, display_name TEXT, enabled INTEGER NOT NULL DEFAULT 1, provider_id INTEGER REFERENCES service_providers(id), model TEXT, parameter_profile_id INTEGER REFERENCES provider_parameters(id), instructions_id INTEGER, memory_enabled INTEGER NOT NULL DEFAULT 1, tools_enabled INTEGER NOT NULL DEFAULT 1, skills_enabled INTEGER NOT NULL DEFAULT 1, tasks_enabled INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, updated_at TEXT);
CREATE UNIQUE INDEX IF NOT EXISTS uq_scope_profiles_global ON scope_profiles(scope_type) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_scope_profiles_scoped ON scope_profiles(scope_type, scope_id) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS instructions (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','guild','channel','dm','group','user','bot_entry','task','roxanne')), scope_id TEXT, body TEXT NOT NULL, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
CREATE UNIQUE INDEX IF NOT EXISTS uq_instructions_global ON instructions(scope_type,name) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_instructions_scoped ON instructions(scope_type,scope_id,name) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS capability_bindings (id INTEGER PRIMARY KEY AUTOINCREMENT, asset_id INTEGER NOT NULL REFERENCES agent_assets(id) ON DELETE CASCADE, scope_type TEXT NOT NULL CHECK (scope_type IN ('global','guild','channel','dm','group','user','bot_entry','task')), scope_id TEXT, enabled INTEGER NOT NULL, reason TEXT, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
CREATE UNIQUE INDEX IF NOT EXISTS uq_capability_bindings_global ON capability_bindings(asset_id,scope_type) WHERE scope_id IS NULL;
CREATE UNIQUE INDEX IF NOT EXISTS uq_capability_bindings_scoped ON capability_bindings(asset_id,scope_type,scope_id) WHERE scope_id IS NOT NULL;
CREATE TABLE IF NOT EXISTS agent_task_runs (id INTEGER PRIMARY KEY AUTOINCREMENT, task_id INTEGER NOT NULL REFERENCES agent_tasks(id) ON DELETE CASCADE, run_status TEXT NOT NULL CHECK (run_status IN ('queued','running','completed','failed','cancelled')), trigger_source TEXT NOT NULL CHECK (trigger_source IN ('scheduler','discord','panel','roxanne','manual')), triggered_by TEXT NOT NULL, scope_type TEXT NOT NULL, scope_id TEXT, provider_id INTEGER REFERENCES service_providers(id), provider_name TEXT, provider_type TEXT, model TEXT, params_json TEXT, instructions_preview TEXT, tools_json TEXT, skills_json TEXT, prompt TEXT NOT NULL, result TEXT, error TEXT, prompt_tokens INTEGER, completion_tokens INTEGER, latency_ms INTEGER, started_at TEXT, completed_at TEXT, created_at TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_agent_task_runs_task_created ON agent_task_runs(task_id, created_at);
CREATE INDEX IF NOT EXISTS idx_agent_task_runs_scope_created ON agent_task_runs(scope_type, scope_id, created_at);
CREATE TABLE IF NOT EXISTS outbound_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, source_type TEXT NOT NULL CHECK (source_type IN ('task','news','command','roxanne','manual')), source_id INTEGER, scope_type TEXT NOT NULL CHECK (scope_type IN ('dm','group','guild','channel')), scope_id TEXT NOT NULL, body TEXT NOT NULL, status TEXT NOT NULL CHECK (status IN ('queued','sent','failed')) DEFAULT 'queued', attempts INTEGER NOT NULL DEFAULT 0, last_error TEXT, created_at TEXT NOT NULL, updated_at TEXT, sent_at TEXT);
CREATE INDEX IF NOT EXISTS idx_outbound_messages_status_created ON outbound_messages(status, created_at);
CREATE TABLE IF NOT EXISTS roxanne_profiles (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE, enabled INTEGER NOT NULL DEFAULT 1, provider_id INTEGER REFERENCES service_providers(id), model TEXT, parameter_profile_id INTEGER REFERENCES provider_parameters(id), reasoning_mode TEXT NOT NULL DEFAULT 'inherit' CHECK (reasoning_mode IN ('inherit','off','on','low','medium','high')), tools_enabled INTEGER NOT NULL DEFAULT 1, system_prompt TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
CREATE TABLE IF NOT EXISTS roxanne_sessions (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT, active_scope_type TEXT, active_scope_id TEXT, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
CREATE TABLE IF NOT EXISTS roxanne_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, session_id INTEGER NOT NULL REFERENCES roxanne_sessions(id) ON DELETE CASCADE, role TEXT NOT NULL CHECK (role IN ('operator','assistant','system','tool')), content TEXT NOT NULL, tool_calls_json TEXT, provider_call_id INTEGER REFERENCES provider_calls(id), timestamp_utc TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS roxanne_memory (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT, body TEXT NOT NULL, tags TEXT, enabled INTEGER NOT NULL DEFAULT 1, created_by TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT);
